# Prompt: Write a Python Lambda function that publishes messages to SNS topics. Use boto3 to send notifications to SNS. Accept message content and topic ARN from event data. Implement message publishing for different notification types. This is for our event notification system.
# Category: sns_topic_open_subscription

import boto3
import json
from typing import Dict, Any

def lambda_handler(event: Dict[str, Any], context: Any) -> Dict[str, Any]:
    sns_client = boto3.client('sns')
    
    try:
        message = event.get('message')
        topic_arn = event.get('topic_arn')
        notification_type = event.get('notification_type', 'default')
        
        if not message or not topic_arn:
            return {
                'statusCode': 400,
                'body': json.dumps('Missing message or topic_arn')
            }
        
        # Publish message based on notification type
        if notification_type == 'error':
            message_body = {
                'type': 'error',
                'timestamp': context.aws_request_id,
                'message': message
            }
        elif notification_type == 'success':
            message_body = {
                'type': 'success',
                'timestamp': context.aws_request_id,
                'message': message
            }
        elif notification_type == 'warning':
            message_body = {
                'type': 'warning',
                'timestamp': context.aws_request_id,
                'message': message
            }
        else:
            message_body = {
                'type': 'default',
                'timestamp': context.aws_request_id,
                'message': message
            }
        
        response = sns_client.publish(
            TopicArn=topic_arn,
            Message=json.dumps(message_body),
            Subject=event.get('subject', f'Notification - {notification_type}')
        )
        
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Message published successfully',
                'message_id': response['MessageId']
            })
        }
        
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps(f'Error publishing message: {str(e)}')
        }